   275→    public void restartForEachItem() throws Exception {
   276→        CountDownLatch countDownLatch = new CountDownLatch(6);
   277→        Flux<Execution> receiveSubflows = TestsUtils.receive(executionQueue, either -> {
   278→            Execution subflowExecution = either.getLeft();
   279→            if (subflowExecution.getFlowId().equals("restart-child") && subflowExecution.getState().getCurrent().isFailed()) {
   280→                countDownLatch.countDown();
   281→            }
   282→        });
   283→
   284→        URI file = storageUpload();
   285→        Map<String, Object> inputs = Map.of("file", file.toString(), "batch", 20);
   286→        final Execution failedExecution = runnerUtils.runOne(MAIN_TENANT, TEST_NAMESPACE, "restart-for-each-item", null,
   287→            (flow, execution1) -> flowIO.readExecutionInputs(flow, execution1, inputs),
   288→            Duration.ofSeconds(30));
   289→        assertThat(failedExecution.getTaskRunList()).hasSize(3);
   290→        assertThat(failedExecution.getState().getCurrent()).isEqualTo(FAILED);
   291→
   292→        // here we must have 1 failed subflows
   293→        assertTrue(countDownLatch.await(1, TimeUnit.MINUTES), "first run of flow should have FAILED");
   294→        receiveSubflows.blockLast();
   295→
   296→        Await.until(
   297→            () -> "first FAILED run of flow should have been persisted",
   298→            () -> getPersistedExecution(MAIN_TENANT, failedExecution.getId())
   299→                .map(exec -> exec.getState().getCurrent() == FAILED)
   300→                .orElse(false),
   301→            Duration.of(100, TimeUnit.MILLISECONDS.toChronoUnit()),
   302→            Duration.of(10, TimeUnit.SECONDS.toChronoUnit())
   303→        );
   304→
   305→        CountDownLatch successLatch = new CountDownLatch(6);
   306→        receiveSubflows = TestsUtils.receive(executionQueue, either -> {
   307→            Execution subflowExecution = either.getLeft();
   308→            if (subflowExecution.getFlowId().equals("restart-child") && subflowExecution.getState().getCurrent().isSuccess()) {
   309→                successLatch.countDown();
   310→            }
   311→        });
   312→
   313→        Execution restarted = executionService.restart(failedExecution, null);
   314→        final Execution successExecution = runnerUtils.awaitExecution(
   315→            e -> e.getState().getCurrent() == State.Type.SUCCESS && e.getFlowId().equals("restart-for-each-item"),
   316→            throwRunnable(() -> executionQueue.emit(restarted)),
   317→            Duration.ofSeconds(20)
   318→        );
   319→        assertThat(successExecution.getTaskRunList()).hasSize(4);
   320→        assertTrue(successLatch.await(1, TimeUnit.MINUTES), "second run of flow should have SUCCESS");
   321→        receiveSubflows.blockLast();
   322→    }
