   324→    private Optional<Execution> getPersistedExecution(String tenant, String executionId) {
   325→        try {
   326→            return Optional.of(executionService.getExecution(tenant, executionId, false));
   327→        } catch (NoSuchElementException e) {
   328→            return Optional.empty();
   329→        }
   330→    }
