package io.kestra.plugin.core.flow;

import io.kestra.core.models.executions.Execution;
import io.kestra.core.models.flows.State;
import io.kestra.core.queues.QueueException;
import io.kestra.core.queues.QueueFactoryInterface;
import io.kestra.core.queues.QueueInterface;
import io.kestra.core.runners.RunnerUtils;
import io.kestra.core.services.ExecutionService;
import io.kestra.core.utils.Await;
import io.kestra.core.utils.TestsUtils;
import jakarta.inject.Inject;
import jakarta.inject.Named;
import lombok.extern.slf4j.Slf4j;
import org.junit.jupiter.api.Test;
import reactor.core.publisher.Flux;

import java.time.Duration;
import java.util.Map;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.TimeoutException;
import java.util.concurrent.atomic.AtomicReference;

import static io.kestra.core.tenant.TenantService.MAIN_TENANT;
import static org.assertj.core.api.Assertions.assertThat;

/**
 * Test to reproduce the ForEachItem task delayed completion bug
 *
 * The bug: ForEachItem task remains in RUNNING state after all child subflows
 * (including afterExecution blocks) have completed successfully.
 */
@Slf4j
public class ForEachItemBugTest {

    static final String TEST_NAMESPACE = "io.kestra.tests";

    @Inject
    @Named(QueueFactoryInterface.EXECUTION_NAMED)
    private QueueInterface<Execution> executionQueue;

    @Inject
    private RunnerUtils runnerUtils;

    @Test
    public void testForEachItemWithAfterExecution() throws TimeoutException, InterruptedException, QueueException {
        CountDownLatch countDownLatch = new CountDownLatch(10); // Expecting 10 subflows
        AtomicReference<Execution> triggered = new AtomicReference<>();

        // Listen for subflow completions
        Flux<Execution> receive = TestsUtils.receive(executionQueue, either -> {
            Execution execution = either.getLeft();
            if (execution.getFlowId().equals("subflow-with-after-execution") &&
                execution.getState().getCurrent().isTerminated()) {
                triggered.set(execution);
                countDownLatch.countDown();

                // Log when each subflow completes (including afterExecution)
                log.info("Subflow {} completed with state: {}",
                    execution.getId(), execution.getState().getCurrent());
            }
        });

        // Create test inputs
        Map<String, Object> inputs = Map.of("itemsCount", 10);

        // Start the parent flow execution
        Execution parentExecution = runnerUtils.runOne(
            MAIN_TENANT,
            TEST_NAMESPACE,
            "parent-flow-with-foreachitem",
            null,
            (flow, execution) -> runnerUtils.getFlowInputOutput().readExecutionInputs(flow, execution, inputs),
            Duration.ofSeconds(60)
        );

        // Wait for all subflows to complete
        boolean allSubflowsCompleted = countDownLatch.await(2, TimeUnit.MINUTES);
        assertThat(allSubflowsCompleted).as("All subflows should complete including afterExecution").isTrue();

        receive.blockLast();

        // Wait additional time to ensure ForEachItem task should transition
        Thread.sleep(5000);

        // Check the parent execution state
        Execution finalExecution = runnerUtils.getExecutionService()
            .getExecution(MAIN_TENANT, parentExecution.getId(), false);

        // The bug: ForEachItem task should not be stuck in RUNNING state
        var forEachItemTaskRun = finalExecution.getTaskRunList()
            .stream()
            .filter(tr -> tr.getTaskId().equals("each"))
            .findFirst()
            .orElseThrow();

        log.info("ForEachItem task state: {}", forEachItemTaskRun.getState().getCurrent());

        // This assertion will fail if the bug exists
        assertThat(forEachItemTaskRun.getState().getCurrent())
            .as("ForEachItem task should transition to SUCCESS after all subflows complete")
            .isEqualTo(State.Type.SUCCESS);

        // Verify the parent execution completes successfully
        assertThat(finalExecution.getState().getCurrent())
            .as("Parent execution should complete successfully")
            .isEqualTo(State.Type.SUCCESS);
    }
}

