   425→    private Executor handleNext(Executor executor) {
   426→        List<NextTaskRun> nextTaskRuns = FlowableUtils
   427→            .resolveSequentialNexts(
   428→                executor.getExecution(),
   429→                ResolvedTask.of(executor.getFlow().getTasks()),
   430→                ResolvedTask.of(executor.getFlow().getErrors()),
   431→                ResolvedTask.of(executor.getFlow().getFinally())
   432→            );
   433→
   434→        if (nextTaskRuns.isEmpty()) {
   435→            return executor;
   436→        }
   437→
   438→        return executor.withTaskRun(
   439→            this.saveFlowableOutput(nextTaskRuns, executor),
   440→            "handleNext"
   441→        );
   442→    }
