   469→    private Executor handleChildWorkerTaskResult(Executor executor) throws Exception {
   470→        if (executor.getExecution().getTaskRunList() == null) {
   471→            return executor;
   472→        }
   473→
   474→        List<WorkerTaskResult> list = new ArrayList<>();
   475→        List<ExecutionDelay> executionDelays = new ArrayList<>();
   476→        List<WorkerTask> onPauses = new ArrayList<>();
   477→
   478→        for (TaskRun taskRun : executor.getExecution().getTaskRunList()) {
   479→            if (taskRun.getState().isRunning()) {
   480→                Optional<WorkerTaskResult> workerTaskResult = this.childWorkerTaskResult(
   481→                    executor.getFlow(),
   482→                    executor.getExecution(),
   483→                    taskRun
   484→                );
   485→
   486→                workerTaskResult.ifPresent(list::add);
   487→            }
   488→
   489→            Task task = executor.getFlow().findTaskByTaskIdOrNull(taskRun.getTaskId());
   490→            /*
   491→             * Check if the task is failed and if it has a retry policy
   492→             */
   493→            if (!executor.getExecution().getState().isRetrying() &&
   494→                taskRun.getState().isFailed() &&
   495→                (task instanceof RunnableTask<?> || task instanceof Subflow)
   496→            ) {
   497→                Instant nextRetryDate = null;
   498→                AbstractRetry.Behavior behavior = null;
   499→
   500→                // Case task has a retry
   501→                if (task.getRetry() != null) {
   502→                    AbstractRetry retry = task.getRetry();
   503→                    behavior = retry.getBehavior();
   504→                    nextRetryDate = behavior.equals(AbstractRetry.Behavior.CREATE_NEW_EXECUTION) ?
   505→                        taskRun.nextRetryDate(retry, executor.getExecution()) :
   506→                        taskRun.nextRetryDate(retry);
   507→                }
   508→                else {
   509→                    // Case parent task has a retry
   510→                    AbstractRetry retry = searchForParentRetry(taskRun, executor);
   511→                    if (retry != null) {
   512→                        behavior = retry.getBehavior();
   513→                        nextRetryDate = behavior.equals(AbstractRetry.Behavior.CREATE_NEW_EXECUTION) ?
   514→                            taskRun.nextRetryDate(retry, executor.getExecution()) :
   515→                            taskRun.nextRetryDate(retry);
   516→                    }
   517→                    // Case flow has a retry
   518→                    else if (executor.getFlow().getRetry() != null) {
   519→                        retry = executor.getFlow().getRetry();
   520→                        behavior = retry.getBehavior();
   521→                        nextRetryDate = behavior.equals(AbstractRetry.Behavior.CREATE_NEW_EXECUTION) ?
   522→                            executionService.nextRetryDate(retry, executor.getExecution()) :
   523→                            taskRun.nextRetryDate(retry);
   524→                    }
   525→                }
   526→
   527→                if (nextRetryDate != null) {
   528→                    ExecutionDelay.ExecutionDelayBuilder executionDelayBuilder = ExecutionDelay.builder()
   529→                        .taskRunId(taskRun.getId())
   530→                        .executionId(executor.getExecution().getId())
   531→                        .date(nextRetryDate)
   532→                        .state(State.Type.RUNNING)
   533→                        .delayType(behavior.equals(AbstractRetry.Behavior.CREATE_NEW_EXECUTION) ?
   534→                            ExecutionDelay.DelayType.RESTART_FAILED_FLOW :
   535→                            ExecutionDelay.DelayType.RESTART_FAILED_TASK);
   536→                    executionDelays.add(executionDelayBuilder.build());
   537→                    executor.withExecution(behavior.equals(AbstractRetry.Behavior.CREATE_NEW_EXECUTION) ?
   538→                            executionService.markWithTaskRunAs(executor.getExecution(), taskRun.getId(), State.Type.RETRIED, true) :
   539→                            executionService.markWithTaskRunAs(executor.getExecution(), taskRun.getId(), State.Type.RETRYING, false),
   540→                        "handleRetryTask");
   541→                    // Prevent workerTaskResult of flowable to be sent
   542→                    // because one of its children is retrying
   543→                    if (taskRun.getParentTaskRunId() != null) {
   544→                        list = list.stream().filter(workerTaskResult -> !workerTaskResult.getTaskRun().getId().equals(taskRun.getParentTaskRunId()))
   545→                            .collect(Collectors.toCollection(ArrayList::new));
   546→                    }
   547→                }
   548→            } else if (task instanceof LoopUntil waitFor && taskRun.getState().isRunning()) {
   549→                if (waitFor.childTaskRunExecuted(executor.getExecution(), taskRun)) {
   550→                    Output newOutput = waitFor.outputs(taskRun);
   551→                    Variables variables = variablesService.of(StorageContext.forTask(taskRun), newOutput);
   552→                    TaskRun updatedTaskRun = taskRun.withOutputs(variables);
   553→                    RunContext runContext = runContextFactory.of(executor.getFlow(), task, executor.getExecution().withTaskRun(updatedTaskRun), updatedTaskRun);
   554→                    List<NextTaskRun> next = ((FlowableTask<?>) task).resolveNexts(runContext, executor.getExecution(), updatedTaskRun);
   555→                    Instant nextDate = waitFor.nextExecutionDate(runContext, executor.getExecution(), updatedTaskRun);
   556→                    if (next.isEmpty()) {
   557→                        return executor;
   558→                    } else if (nextDate != null) {
   559→                        executionDelays.add(ExecutionDelay.builder()
   560→                            .taskRunId(taskRun.getId())
   561→                            .executionId(executor.getExecution().getId())
   562→                            .date(nextDate)
   563→                            .state(State.Type.RUNNING)
   564→                            .delayType(ExecutionDelay.DelayType.CONTINUE_FLOWABLE)
   565→                            .build());
   566→                        Execution execution = executionService.pauseFlowable(executor.getExecution(), updatedTaskRun);
   567→                        executor.withExecution(execution, "pauseLoop");
   568→                    } else {
   569→                        executor.withExecution(executor.getExecution().withTaskRun(updatedTaskRun), "handleWaitFor");
   570→                    }
   571→                }
   572→            } else if (task instanceof Pause pause && pause.getOnPause() != null) {
   573→                // if a Pause task defines an onPause, we must create a TaskRun and a WorkerTask
   574→                RunContext runContext = runContextFactory.of(executor.getFlow(), executor.getExecution());
   575→                onPauses.add(WorkerTask.builder()
   576→                    .runContext(runContext)
   577→                    .taskRun(TaskRun.of(
   578→                        executor.getExecution(),
   579→                        ResolvedTask.of(pause.getOnPause())
   580→                    ))
   581→                    .task(pause.getOnPause())
   582→                    .executionKind(executor.getExecution().getKind())
   583→                    .build());
   584→            }
   585→
   586→            // If the task is retrying
   587→            // make sure that the workerTaskResult of the parent task is not sent
   588→            if (taskRun.getState().isRetrying() && taskRun.getParentTaskRunId() != null) {
   589→                list = list.stream().filter(workerTaskResult -> !workerTaskResult.getTaskRun().getId().equals(taskRun.getParentTaskRunId()))
   590→                    .collect(Collectors.toCollection(ArrayList::new));
   591→            }
   592→        }
   593→
   594→        metricRegistry
   595→            .counter(MetricRegistry.METRIC_EXECUTOR_EXECUTION_DELAY_CREATED_COUNT, MetricRegistry.METRIC_EXECUTOR_EXECUTION_DELAY_CREATED_COUNT_DESCRIPTION, metricRegistry.tags(executor.getExecution()))
   596→            .increment(executionDelays.size());
   597→
   598→        executor.withWorkerTaskDelays(executionDelays, "handleChildWorkerTaskDelay");
   599→
   600→        if (list.isEmpty()) {
   601→            return executor;
   602→        }
   603→
   604→
   605→        if (!onPauses.isEmpty()) {
   606→            List<TaskRun> taskRuns = onPauses.stream().map(WorkerTask::getTaskRun).toList();
   607→            executor.withTaskRun(taskRuns, "handlePauses");
   608→            executor.withWorkerTasks(onPauses, "handlePauses");
   609→        }
   610→
   611→        executor = this.handlePausedDelay(executor, list);
   612→
   613→        this.addWorkerTaskResults(executor, list);
   614→
   615→        return executor;
   616→    }
   617→
   618→    private AbstractRetry searchForParentRetry(TaskRun taskRun, Executor executor) {
   619→        // search in all parents, recursively
   620→        if (taskRun.getParentTaskRunId() != null) {
   621→            String taskId = taskRun.getTaskId();
   622→            Task parentTask;
   623→            do {
   624→                parentTask = executor.getFlow().findParentTasksByTaskId(taskId);
   625→                if (parentTask != null) {
   626→                    taskId = parentTask.getId();
   627→                }
   628→            } while (parentTask != null && parentTask.getRetry() == null);
   629→
   630→            if (parentTask != null) {
   631→                return parentTask.getRetry();
   632→            }
   633→        }
   634→
   635→        return null;
   636→    }
   637→
   638→    private Executor handlePausedDelay(Executor executor, List<WorkerTaskResult> workerTaskResults) throws InternalException {
   639→        if (workerTaskResults
   640→            .stream()
   641→            .noneMatch(workerTaskResult -> workerTaskResult.getTaskRun().getState().getCurrent() == State.Type.PAUSED)) {
   642→            return executor;
   643→        }
   644→
   645→        List<ExecutionDelay> list = workerTaskResults
   646→            .stream()
   647→            .filter(workerTaskResult -> workerTaskResult.getTaskRun().getState().getCurrent() == State.Type.PAUSED)
   648→            .map(throwFunction(workerTaskResult -> {
   649→                Task task = executor.getFlow().findTaskByTaskId(workerTaskResult.getTaskRun().getTaskId());
   650→
   651→                if (task instanceof Pause pauseTask) {
   652→                    if (pauseTask.getPauseDuration() != null || pauseTask.getTimeout() != null) {
   653→                        RunContext runContext = runContextFactory.of(executor.getFlow(), executor.getExecution());
   654→                        Duration duration = runContext.render(pauseTask.getPauseDuration()).as(Duration.class).orElse(null);
   655→                        Duration timeout = runContext.render(pauseTask.getTimeout()).as(Duration.class).orElse(null);
   656→                        Pause.Behavior behavior  = runContext.render(pauseTask.getBehavior()).as(Pause.Behavior.class).orElse(Pause.Behavior.RESUME);
   657→                        if (duration != null || timeout != null) { // rendering can lead to null, so we must re-check here
   658→                            // if duration is set, we use it, and we use the Pause behavior as a state
   659→                            // if no duration, we use the standard timeout property and use FAILED as the target state
   660→                            return ExecutionDelay.builder()
   661→                                .taskRunId(workerTaskResult.getTaskRun().getId())
   662→                                .executionId(executor.getExecution().getId())
   663→                                .date(workerTaskResult.getTaskRun().getState().maxDate().plus(duration != null ? duration : timeout))
   664→                                .state(duration != null ? behavior.mapToState() : State.Type.fail(pauseTask))
   665→                                .delayType(ExecutionDelay.DelayType.RESUME_FLOW)
   666→                                .build();
   667→                        }
   668→                    }
   669→                }
   670→
   671→                return null;
   672→            }))
   673→            .filter(Objects::nonNull)
   674→            .toList();
   675→
   676→        if (executor.getExecution().getState().getCurrent() != State.Type.PAUSED) {
   677→            return executor
   678→                .withExecution(executor.getExecution().withState(State.Type.PAUSED), "handlePausedDelay")
   679→                .withWorkerTaskDelays(list, "handlePausedDelay");
   680→        }
   681→
   682→        return executor.withWorkerTaskDelays(list, "handlePausedDelay");
   683→    }
