   744→            return executor;
   745→        }
   746→
   747→        List<ResolvedTask> currentTasks = executor.getExecution().findTaskDependingFlowState(
   748→            ResolvedTask.of(executor.getFlow().getTasks()),
   749→            ResolvedTask.of(executor.getFlow().getErrors()),
   750→            ResolvedTask.of(executor.getFlow().getFinally())
   751→        );
   752→
   753→        if (!executor.getExecution().isTerminated(currentTasks)) {
   754→            return executor;
   755→        }
   756→
   757→        return this.onEnd(executor);
   758→    }
