   788→    private Executor handleWorkerTask(final Executor executor) throws InternalException {
   789→        if (executor.getExecution().getTaskRunList() == null || executor.getExecution().getState().getCurrent() == State.Type.KILLING) {
   790→            return executor;
   791→        }
   792→
   793→        Optional<TextMapPropagator> textMapPropagator = openTelemetry
   794→            .map(OpenTelemetry::getPropagators)
   795→            .map(ContextPropagators::getTextMapPropagator);
   796→
   797→        // submit TaskRun when receiving created, must be done after the state execution store
   798→        Map<Boolean, List<WorkerTask>> workerTasks = executor.getExecution()
   799→            .getTaskRunList()
   800→            .stream()
   801→            .filter(taskRun -> taskRun.getState().getCurrent().isCreated() && executor.getExecution().getFixtureForTaskRun(taskRun).isEmpty())
   802→            .map(throwFunction(taskRun -> {
   803→                    Task task = executor.getFlow().findTaskByTaskId(taskRun.getTaskId());
   804→                    RunContext runContext = runContextFactory.of(executor.getFlow(), task, executor.getExecution(), taskRun);
   805→
   806→                    // inject the traceparent into the run context
   807→                    textMapPropagator.ifPresent(propagator -> propagator.inject(Context.current(), runContext, RunContextTextMapSetter.INSTANCE));
   808→
   809→                    WorkerTask workerTask = WorkerTask.builder()
   810→                        .runContext(runContext)
   811→                        .taskRun(taskRun)
   812→                        .task(task)
   813→                        .executionKind(executor.getExecution().getKind())
   814→                        .build();
   815→                    // Get worker group
   816→                    Optional<WorkerGroup> workerGroup = workerGroupService.resolveGroupFromJob(executor.getFlow(), workerTask);
   817→                    if (workerGroup.isPresent()) {
   818→                        // Check if the worker group exist
   819→                        String tenantId = executor.getFlow().getTenantId();
   820→                        String workerGroupKey = runContext.render(workerGroup.get().getKey());
   821→                        if (workerGroupExecutorInterface.isWorkerGroupExistForKey(workerGroupKey, tenantId)) {
   822→                            // Check whether at-least one worker is available
   823→                            if (workerGroupExecutorInterface.isWorkerGroupAvailableForKey(workerGroupKey)) {
   824→                                return workerTask;
   825→                            } else {
   826→                                WorkerGroup.Fallback fallback = workerGroup.map(wg -> wg.getFallback()).orElse(WorkerGroup.Fallback.WAIT);
   827→                                return switch(fallback) {
   828→                                    case FAIL -> {
   829→                                        runContext.logger()
   830→                                            .error("No workers are available for worker group '{}', failing the task.", workerGroupKey);
   831→                                        yield workerTask.withTaskRun(workerTask.getTaskRun().fail());
   832→                                    }
   833→                                    case CANCEL -> {
   834→                                        runContext.logger()
   835→                                            .info("No workers are available for worker group '{}', canceling the task.", workerGroupKey);
   836→                                        yield workerTask.withTaskRun(workerTask.getTaskRun().withState(State.Type.CANCELLED));
   837→                                    }
   838→                                    case WAIT -> {
   839→                                        runContext.logger()
   840→                                            .info("No workers are available for worker group '{}', waiting for one to be available.", workerGroupKey);
   841→                                        yield workerTask;
   842→                                    }
   843→                                };
   844→                            }
   845→                        } else {
   846→                            runContext.logger()
   847→                                .error("Cannot run task. No worker group exist for key '{}'.", workerGroupKey);
   848→                            // fail the task-run because no worker can run the task
   849→                            return workerTask.withTaskRun(workerTask.getTaskRun().fail());
   850→                        }
   851→                    } else {
   852→                        return workerTask;
   853→                    }
   854→                })
   855→            )
   856→            .collect(Collectors.groupingBy(workerTask -> workerTask.getTaskRun().getState().isFailed() || workerTask.getTaskRun().getState().getCurrent() == State.Type.CANCELLED));
   857→
   858→        // mock WorkerTaskResult for mocked execution
   859→        // submit TaskRun when receiving created, must be done after the state execution store
   860→        boolean hasMockedWorkerTask = false;
   861→        record FixtureAndTaskRun(TaskFixture fixture, TaskRun taskRun) {}
   862→        if (executor.getExecution().getFixtures() != null) {
   863→            RunContext runContext = runContextFactory.of(executor.getFlow(), executor.getExecution());
   864→            List<WorkerTaskResult> workerTaskResults = executor.getExecution()
   865→                .getTaskRunList()
   866→                .stream()
   867→                .filter(taskRun -> taskRun.getState().getCurrent().isCreated())
   868→                .flatMap(taskRun -> executor.getExecution().getFixtureForTaskRun(taskRun).stream().map(fixture -> new FixtureAndTaskRun(fixture, taskRun)))
   869→                .map(throwFunction(fixtureAndTaskRun -> WorkerTaskResult.builder()
   870→                    .taskRun(fixtureAndTaskRun.taskRun()
   871→                        .withState(Optional.ofNullable(fixtureAndTaskRun.fixture().getState()).orElse(State.Type.SUCCESS))
   872→                        .withOutputs(
   873→                            variablesService.of(StorageContext.forTask(fixtureAndTaskRun.taskRun),
   874→                                fixtureAndTaskRun.fixture().getOutputs() == null ? null : runContext.render(fixtureAndTaskRun.fixture().getOutputs()))
   875→                        )
   876→                    )
   877→                    .build()
   878→                ))
   879→                .toList();
   880→
   881→            hasMockedWorkerTask = !workerTaskResults.isEmpty();
   882→            this.addWorkerTaskResults(executor, workerTaskResults);
   883→        }
   884→
   885→        if (workerTasks.isEmpty() || hasMockedWorkerTask) {
   886→            return executor;
   887→        }
   888→
   889→        Executor executorToReturn = executor;
   890→
   891→        // suspend on breakpoint: if a breakpoint is for a CREATED taskrun, set the execution state to BREAKPOINT and ends here
   892→        if (!ListUtils.isEmpty(executor.getExecution().getBreakpoints())) {
   893→            List<Breakpoint> breakpoints = executor.getExecution().getBreakpoints();
   894→            if (executor.getExecution()
   895→                .getTaskRunList()
   896→                .stream()
   897→                .anyMatch(taskRun -> shouldSuspend(taskRun, breakpoints))
   898→            ) {
   899→                List<TaskRun> newTaskRuns = executor.getExecution().getTaskRunList().stream().map(
   900→                    taskRun -> {
   901→                        if (shouldSuspend(taskRun, breakpoints)) {
   902→                            return taskRun.withState(State.Type.BREAKPOINT);
   903→                        }
   904→                        return taskRun;
   905→                    }
   906→                ).toList();
   907→                Execution newExecution = executor.getExecution().withTaskRunList(newTaskRuns).withState(State.Type.BREAKPOINT);
   908→                executorToReturn = executorToReturn.withExecution(newExecution, "handleBreakpoint");
   909→                logService.logExecution(
   910→                    newExecution,
   911→                    Level.INFO,
   912→                    "Flow is suspended at a breakpoint."
   913→                );
   914→            }
   915→        }
   916→
   917→        // Ends FAILED or CANCELLED task runs by creating worker task results
   918→        List<WorkerTask> endedTasks = workerTasks.get(true);
   919→        if (endedTasks != null && !endedTasks.isEmpty()) {
   920→            List<WorkerTaskResult> failed = endedTasks
   921→                .stream()
   922→                .map(workerTask -> WorkerTaskResult.builder().taskRun(workerTask.getTaskRun()).build())
   923→                .toList();
   924→
   925→            this.addWorkerTaskResults(executor, failed);
   926→        }
   927→
   928→        // Send other TaskRun to the worker (create worker tasks)
   929→        List<WorkerTask> processingTasks = workerTasks.get(false);
   930→        if (processingTasks != null && !processingTasks.isEmpty() && !executor.getExecution().getState().isBreakpoint()) {
   931→            executorToReturn = executorToReturn.withWorkerTasks(processingTasks, "handleWorkerTask");
   932→
   933→            metricRegistry.counter(MetricRegistry.METRIC_EXECUTOR_TASKRUN_CREATED_COUNT, MetricRegistry.METRIC_EXECUTOR_TASKRUN_CREATED_COUNT_DESCRIPTION, metricRegistry.tags(executor.getExecution())).increment(processingTasks.size());
   934→        }
   935→
   936→        return executorToReturn;
   937→    }
