   939→    private boolean shouldSuspend(TaskRun taskRun, List<Breakpoint> breakpoints) {
   940→        return taskRun.getState().getCurrent().isCreated() && breakpoints.stream()
   941→                .anyMatch(breakpoint -> taskRun.getTaskId().equals(breakpoint.getId()) && (breakpoint.getValue() == null || Objects.equals(taskRun.getValue(), breakpoint.getValue())));
   942→    }
