  1084→    public void addWorkerTaskResult(Executor executor, Supplier<Flow> flow, WorkerTaskResult workerTaskResult) throws InternalException {
  1085→        // dynamic tasks
  1086→        Execution newExecution = this.addDynamicTaskRun(
  1087→            executor.getExecution(),
  1088→            flow,
  1089→            workerTaskResult
  1090→        );
  1091→        if (newExecution != null) {
  1092→            executor.withExecution(newExecution, "addDynamicTaskRun");
  1093→        }
  1094→
  1095→        TaskRun taskRun = workerTaskResult.getTaskRun();
  1096→        newExecution = executor.getExecution().withTaskRun(taskRun);
  1097→        // If the worker task result is killed, we must check if it has a parents to also kill them if not already done.
  1098→        // Running flowable tasks that have child tasks running in the worker will be killed thanks to that.
  1099→        if (taskRun.getState().getCurrent() == State.Type.KILLED && taskRun.getParentTaskRunId() != null) {
  1100→            newExecution = executionService.killParentTaskruns(taskRun, newExecution);
  1101→        }
  1102→        executor.withExecution(newExecution, "addWorkerTaskResult");
  1103→        if (taskRun.getState().isTerminated()) {
  1104→            log.trace("TaskRun terminated: {}", taskRun);
  1105→            workerJobRunningStateStore.deleteByKey(taskRun.getId());
  1106→            metricRegistry
  1107→                .counter(
  1108→                    MetricRegistry.METRIC_EXECUTOR_TASKRUN_ENDED_COUNT,
  1109→                    MetricRegistry.METRIC_EXECUTOR_TASKRUN_ENDED_COUNT_DESCRIPTION,
  1110→                    metricRegistry.tags(workerTaskResult)
  1111→                )
  1112→                .increment();
  1113→
  1114→            metricRegistry
  1115→                .timer(
  1116→                    MetricRegistry.METRIC_EXECUTOR_TASKRUN_ENDED_DURATION,
  1117→                    MetricRegistry.METRIC_EXECUTOR_TASKRUN_ENDED_DURATION_DESCRIPTION,
  1118→                    metricRegistry.tags(workerTaskResult)
  1119→                )
  1120→                .record(taskRun.getState().getDuration());
  1121→        }
  1122→    }
