  1124→    // Note: as the flow is only used in an error branch and it can take time to load, we pass it thought a Supplier
  1125→    private Execution addDynamicTaskRun(Execution execution, Supplier<Flow> flow, WorkerTaskResult workerTaskResult) throws InternalException {
  1126→        ArrayList<TaskRun> taskRuns = new ArrayList<>(ListUtils.emptyOnNull(execution.getTaskRunList()));
  1127→
  1128→        // declared dynamic tasks
  1129→        if (!ListUtils.isEmpty(workerTaskResult.getDynamicTaskRuns())) {
  1130→            taskRuns.addAll(workerTaskResult.getDynamicTaskRuns());
  1131→        }
  1132→
  1133→        // if parent, can be a Worker task that generate dynamic tasks
  1134→        if (workerTaskResult.getTaskRun().getParentTaskRunId() != null) {
  1135→            try {
  1136→                execution.findTaskRunByTaskRunId(workerTaskResult.getTaskRun().getId());
  1137→            } catch (InternalException e) {
  1138→                TaskRun parentTaskRun = execution.findTaskRunByTaskRunId(workerTaskResult.getTaskRun().getParentTaskRunId());
  1139→                Task parentTask = flow.get().findTaskByTaskId(parentTaskRun.getTaskId());
  1140→
  1141→                if (parentTask instanceof WorkingDirectory) {
  1142→                    taskRuns.add(workerTaskResult.getTaskRun());
  1143→                }
  1144→            }
  1145→        }
  1146→
  1147→        return taskRuns.size() > execution.getTaskRunList().size() ? execution.withTaskRunList(taskRuns) : null;
  1148→    }
