  1150→    public boolean canBePurged(final Executor executor) {
  1151→        return executor.getExecution().isDeleted() || (
  1152→            executor.getFlow() != null &&
  1153→                // is terminated
  1154→                executionService.isTerminated(executor.getFlow(), executor.getExecution())
  1155→                // we don't purge pause execution in order to be able to restart automatically in case of delay
  1156→                && executor.getExecution().getState().getCurrent() != State.Type.PAUSED
  1157→                // we don't purge killed execution in order to have feedback about child running tasks
  1158→                // this can be killed lately (after the executor kill the execution), but we want to keep
  1159→                // feedback about the actual state (killed or not)
  1160→                // @TODO: this can lead to infinite state store for most executor topic
  1161→                && executor.getExecution().getState().getCurrent() != State.Type.KILLED
  1162→        );
  1163→    }
