  1255→    /**
  1256→     * Handle flow ExecutionChangedSLA on an executor.
  1257→     * If there are SLA violations, it will take care of updating the execution based on the SLA behavior.
  1258→     * @see #processViolation(RunContext, Executor, Violation)
  1259→     * <p>
  1260→     * WARNING: ATM, only the first violation will update the execution.
  1261→     */
  1262→    public Executor handleExecutionChangedSLA(Executor executor) throws QueueException {
  1263→        if (executor.getFlow() == null || ListUtils.isEmpty(executor.getFlow().getSla()) || executor.getExecution().getState().isTerminated()) {
  1264→            return executor;
  1265→        }
  1266→
  1267→        RunContext runContext = runContextFactory.of(executor.getFlow(), executor.getExecution());
  1268→        List<Violation> violations = slaService.evaluateExecutionChangedSLA(runContext, executor.getFlow(), executor.getExecution());
  1269→        if (!violations.isEmpty()) {
  1270→            metricRegistry
  1271→                .counter(MetricRegistry.METRIC_EXECUTOR_SLA_VIOLATION_COUNT, MetricRegistry.METRIC_EXECUTOR_SLA_VIOLATION_COUNT_DESCRIPTION, metricRegistry.tags(executor.getExecution()))
  1272→                .increment(violations.size());
  1273→
  1274→            // For now, we only consider the first violation to be capable of updating the execution.
  1275→            // Other violations would only be logged.
  1276→            Violation violation = violations.getFirst();
  1277→            return processViolation(runContext, executor, violation);
  1278→        }
  1279→
  1280→        return executor;
  1281→    }
  1282→
  1283→    /**
  1284→     * Process an SLA violation on an executor:
  1285→     * - If behavior is FAIL or CANCEL: kill the execution, then return it with the new state.
  1286→     * - If behavior is NONE: do nothing and return an unmodified executor.
  1287→     * <p>
  1288→     * Then, if there are labels, they are added to the SLA (modifying the executor)
  1289→     */
  1290→    public Executor processViolation(RunContext runContext, Executor executor, Violation violation) throws QueueException {
  1291→        boolean hasChanged = false;
  1292→        Execution newExecution = switch (violation.behavior()) {
  1293→            case FAIL -> {
  1294→                runContext.logger().error("Execution failed due to SLA '{}' violated: {}", violation.slaId(), violation.reason());
  1295→                hasChanged = true;
  1296→                yield markAs(executor.getExecution(), State.Type.FAILED);
  1297→            }
  1298→            case CANCEL -> {
  1299→                hasChanged = true;
  1300→                yield markAs(executor.getExecution(), State.Type.CANCELLED);
  1301→            }
  1302→            case NONE -> executor.getExecution();
  1303→        };
  1304→
  1305→        if (!ListUtils.isEmpty(violation.labels()) && !LabelService.containsAll(executor.getExecution().getLabels(), violation.labels())) {
  1306→            List<Label> labels = new ArrayList<>(newExecution.getLabels());
  1307→            labels.addAll(violation.labels());
  1308→            hasChanged = true;
  1309→            newExecution = newExecution.withLabels(labels);
  1310→        }
  1311→
  1312→        if (hasChanged) {
  1313→            return executor.withExecution(newExecution, "SLAViolation");
  1314→        }
  1315→        return executor;
  1316→    }
  1317→
  1318→    private Execution markAs(Execution execution, State.Type state) throws QueueException {
  1319→        Execution newExecution = execution.findLastNotTerminated()
  1320→            .map(taskRun -> {
  1321→                try {
  1322→                    return execution.withTaskRun(taskRun.withState(state));
  1323→                } catch (InternalException e) {
  1324→                    // in case we cannot update the last not terminated task run, we ignore it
  1325→                    return execution;
  1326→                }
  1327→            })
  1328→            .orElse(execution)
  1329→            .withState(state);
  1330→
  1331→        killQueue.emit(ExecutionKilledExecution
  1332→            .builder()
  1333→            .state(ExecutionKilled.State.REQUESTED)
  1334→            .executionState(state)
  1335→            .executionId(execution.getId())
  1336→            .isOnKillCascade(true)
  1337→            .tenantId(execution.getTenantId())
  1338→            .build()
  1339→        );
  1340→
  1341→        return newExecution;
  1342→    }
  1343→}
